INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-6e2f88c7-moex-00134', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '關於人格權受侵害時，被害人得主張之救濟，下列敘述，何者錯誤？', '["針對現實之人格權侵害，被害人得請求侵害除去", "人格權有受侵害之虞時，被害人得請求侵害防止", "因人格權受侵害而發生之損害，於法律有明文特別規定者為限，被害人得請求損害賠償", "被害人不以法律有明文特別規定者為限，得請求慰撫金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00135', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '基於除斥期間與消滅時效之規定，下列關於權利行使之期間限制之敘述，何者錯誤？', '["以抵押權擔保之債權，於被擔保債權消滅時效完成後5年間應行使抵押權，此期間之限制，為 除斥期間", "買受人因物有瑕疵得向出賣人請求減少價金之請求權，應於物交付後5年期間內行使之限制， 為消滅時效", "承攬人對定作人之損害賠償請求權，因其原因發生後1年間應行使之期間限制，為消滅時效", "醫生之診費及墊款請求權之期間限制，為消滅時效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00136', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '對於現時不法之侵害為防衛自己或他人之權利，於不逾越必要程度範圍內為反擊行為者。此種反 擊行為稱為：', '["正當防衛", "緊急避難", "自助行為", "不當得利"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00137', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '下列關於債務不履行歸責事由之敘述，何者錯誤？', '["債務人就其故意或過失之行為，應負責任", "甲將其幼兒A托鄰居乙照顧，由於乙並未收費，遂與甲約定免除其重大過失責任。其後因乙之 重大過失致A走失，致甲支出龐大協尋費用，然因乙並無故意，甲無法向乙請求損害賠償", "甲委託律師乙代為訂立房屋買賣契約，乙若收取報酬，則應以善良管理人之注意義務處理委任 事務", "依民法第606條規定，旅店之場所主人必須負通常事變責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00138', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '下列關於同時履行抗辯權與不安抗辯權之敘述，何者錯誤？', '["自己有先為給付義務者，則無同時履行抗辯權", "自己有先為給付義務者，則無不安抗辯權", "當事人之一方，應向他方先為給付者，如他方之財產，於訂約後顯形減少，有難為對待給付之 虞時，如他方已為對待給付，則不得拒絕自己之給付", "當事人之一方，應向他方先為給付者，如他方之財產，於訂約後顯形減少，有難為對待給付之 虞時，如他方已提出擔保，則不得拒絕自己之給付"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00139', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲乙丙丁戊共同對A有一連帶債務新臺幣（下同）1000萬元，但並未約定分擔部分。丁得知丙對 A有500萬債權，便向A表示要以之抵銷連帶債務，之後A又主動免除甲之債務。下列敘述，何 者錯誤？', '["未約定債務之分擔部分，所以5人均分", "丁先向A表示要以丙對其之債權，抵銷該連帶債務，所以連帶債務得因此減少200萬", "丁主張以丙債權抵銷連帶債務、再加上A免除甲之債務，之後若乙清償剩下之全部債務，其應 共清償300萬元", "乙清償全部債務後，得對於其他債務人行使求償權，但發現戊因躲債潛逃海外遍尋不著。關於 戊的債務部分，由乙與甲丙丁按比例分擔之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00140', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲有一宗 A 地，為雙重買賣；先與乙訂立買賣契約，將 A 地交付予乙；嗣後又與丙訂立買賣契 約，將A地所有權移轉登記給丙。何人取得A地之所有權？', '["乙", "丙", "乙與丙分別共有", "乙與丙公同共有 13740、40140 41140"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00141', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '依民法規定，下列關於出租人及承租人權利義務及責任之敘述，何者錯誤？', '["耕作地之出租人不得預收租金", "就租賃物應納之一切稅捐，由承租人負擔", "租賃物為動物者，其飼養費由承租人負擔", "租賃物之修繕，除契約另有訂定或另有習慣外，由出租人負擔"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00142', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '試驗買賣，為以買受人之承認標的物為停止條件而訂立之契約。下列何種情形，不得視為承認？', '["買受人不經試驗，即拒絕承認", "標的物因試驗已交付於買受人，而買受人不交還其物", "於約定期限，買受人不為拒絕之表示", "出賣人所定之相當期限內，買受人不為拒絕之表示"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00143', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲贈與Ａ畫給乙，乙允受之。下列敘述，何者正確？', '["贈與物之權利移轉前，或移轉後，甲皆得任意撤銷其贈與", "經公證之贈與，縱使受贈人乙對贈與人甲有故意傷害行為，仍不得撤銷", "乙因故意傷害行為導致贈與人甲死亡，甲之繼承人得於知有撤銷原因之時起，6個月內撤銷贈與", "贈與人於贈與約定後，經濟情況顯有變更，致影響生計時，得撤銷贈與"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL)
